// TestESOFinalizerConstant pins the exact finalizer string the handler looks
// for on each backup PushSecret. Changing this string in isolation would
// silently break the Pass-0 adoption gate against real ESO-managed
// PushSecrets — pin it here so the drift shows up as a test failure
// (CC-0091, REQ-007).
func TestESOFinalizerConstant(t *testing.T) {
	g := NewGomegaWithT(t)
	g.Expect(esoPushSecretFinalizer).To(Equal("pushsecret.externalsecrets.external-secrets.io/finalizer"))
}
